const raw = $input.first().json;
const html = typeof raw === 'string' ? raw : (raw.data || raw.body || JSON.stringify(raw));

// Extract posts from Telegram public preview HTML
const postRegex = /<div[^>]*class="[^"]*tgme_widget_message_text[^"]*"[^>]*>([\s\S]*?)</div>/g;
const posts = [];
let m;
while ((m = postRegex.exec(html)) !== null && posts.length < 15) {
  let txt = m[1]
    .replace(/<br\s*/?>/gi, '
')
    .replace(/<a[^>]*>([\s\S]*?)</a>/g, '$1')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ')
    .trim();
  if (txt.length > 80) posts.push(txt.slice(0, 2500));
}

// Hardcoded author samples (from @denichel) — used as base + any fresh posts from preview
const AUTHOR_SAMPLES = [
  `Созидать и делиться.

Совершенно спонтанно посетили музейный комплекс УГМК в Верхней Пышме. 

Интерактив и тонны информации на 17 гектарах, сколько трудов вложено, остается только догадываться. Но множество экспозиций объективно стоят десятки миллионов рублей, а то и долларов. Внимание к деталям и масштаб - это очень круто.

Наверняка, многие были здесь, или слышали о существовании музея в Верхней Пышме.

Открытое Меценатство - это отдельный вид искусства.

Но вот, что радует: В Верхней Пышме и в регионе в целом видно, что поддержку культурным инициативам воспринимают не как дань моде, а как стратегию. Власти создают условия, ресурсы, инфраструктуру.

Видимо понимают, что туристы и желание вернуться создают финансовый поток в регион. 

Летом мы обязательно вернемся сюда, параллельно посетив Нижний Тагил (завод музей), Невьянск (башню). Если доделают «Белый Дом» в Кыштыме.`,
  `Как атомная история поменяла взгляд на блог или почему сегодня многие отпишутся (или нет)?

Наверно в любом деле бывают застои, тем более в творческом. Пост без картинок, эмоджи и всякого такого. Немного истории, а потом выводы...

Следующей темой должен стать фильм про "Маяк". Да в ограниченном коридоре тем, кажется все исчерпаны. Год, два, три, рассказывать про город прикольно, если он отвечает тем же, но не вышло, и я не про деньги, я про возможности, эксклюзивы и отсутствие рамок, да и интересов стало много больше, а копаться хочется в том, что интересно мне.

Да, часть людей, привыкших к «старому контенту», может уйти. Это нормально. Зато останутся те, кому интересен не только формат, но и путь автора. И именно с ними можно двигаться дальше, пробовать новое и говорить о многом.

Поэтому я и продолжаю. Не потому что «надо», а потому что иначе уже не получается.`,
  `289 лет назад 2 сентября 1736 года полковник Алексей Тевкелев отправил доношение (фото 1) об основании крепости (фото 2) между Миасской и Чебаркульской крепостями (фото 3).

Почему же мы празднуем сегодня? Да всё просто! В 1918 году Ленин перевел Россию на Григорианский календарь (до этого момента страна жила по Юлианскому), чтобы удобнее было вести дела с Европой. 

А так как он (календарь) был вперед на 11 дней, всё приплюсовалось, и сегодня, мы отмечаем ДР города 13 числа по новому стилю. 

С момента основания Челябинской крепости на реке Миасс прошло почти три века, и за это время наш город стал символом труда, силы и духа - Город металлургов и машиностроителей.`
];

const combined = [...AUTHOR_SAMPLES, ...posts.filter(p => p.length > 150).slice(0, 5)];
const styleRef = combined.slice(0, 8).map((p, i) => '--- Пример ' + (i + 1) + ' ---
' + p).join('

');

return [{ json: { styleRef, sampleCount: combined.length, freshFromChannel: posts.length } }];

const res = $input.first().json;
const content = res.content || [];

let jsonText = '';
for (const c of content.slice().reverse()) {
  if (c.type === 'text' && c.text) {
    jsonText = c.text;
    break;
  }
}

if (!jsonText) return [{ json: { skip: true, reason: 'no text from Claude' } }];

jsonText = jsonText.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();
const jm = jsonText.match(/\{[\s\S]*\}/);
if (jm) jsonText = jm[0];

let parsed;
try { parsed = JSON.parse(jsonText); } catch(e) { return [{ json: { skip: true, reason: 'parse error' } }]; }

const posts = parsed.posts || [];
const searchedCount = parsed.searched_count || 0;
if (!posts.length) return [{ json: { skip: true, reason: 'empty posts' } }];

// Dedup full digest by day (don't make 2 digests per day)
const store = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);
if (store.lastChelDigest === today && !parsed._force) {
  // Allow re-trigger for same day but different content via manual trigger — use dedupe by headline set hash
}
store.lastChelDigest = today;

const styleRef = $('Prep Research Body').first().json.styleRef || '';

return [{ json: { posts, searchedCount, styleRef, skip: false, today } }];

const res = $input.first().json;
let post = '';
if (res.content && Array.isArray(res.content)) {
  const textBlock = res.content.find(c => c.type === 'text');
  post = textBlock?.text?.trim() || '';
}
post = post.replace(/@che_v_che\s*$/i, '').trim();
post += '\n\n@che_v_che';
const id = 'chel_' + Date.now() + '_' + Math.random().toString(36).slice(2,7);
return [{ json: { post, id } }];
